import {
  addPostActionCreator,
  addPostMessageActionCreator,
} from "../../Redux/profile-reducer";
import MyPosts from "./MyPosts";

import { connect } from "react-redux";

const MyPostsContainer = (props) => {
  let postPost = (postMessage) => {
    let action = addPostActionCreator(postMessage);
    props.dispatch(action);
  };

  return <MyPosts addPost={postPost} postData={props.postData} />;
};

let mapStateToProps = (state) => {
  return {
    postData: state.profilePage.postData,
  };
};

let mapDispatchToProps = (dispatch) => {
  return {
    addPost: () => {
      dispatch(addPostActionCreator());
    },
    addPostMessage: (postMessage) => {
      let action = addPostMessageActionCreator(postMessage);
      dispatch(addPostMessageActionCreator(action));
    },
  };
};

const SuperMyPostsContainer = connect(
  mapStateToProps,
  mapDispatchToProps
)(MyPosts);

export default SuperMyPostsContainer;
